from typing import Optional

from pydantic import BaseModel, ConfigDict


class GetObservationsInput(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    variable_dcid: str
    place_dcid: str
    child_place_type: Optional[str] = None
    source_override: Optional[str] = None
    date: Optional[str] = "latest"
    date_range_start: Optional[str] = None
    date_range_end: Optional[str] = None


class SearchIndicatorsInput(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    query: str
    places: Optional[list[str]] = None
    parent_place: Optional[str] = None
    per_search_limit: Optional[int] = 10
    include_topics: Optional[bool] = True
    maybe_bilateral: Optional[bool] = False
